-- W1.6 questions batch 4888/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-6e2f88c7-moex-00072', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲列乙為被告，起訴請求法院判決命乙應給付甲新臺幣（下同）500 萬
元。主張之事實及理由為：丙曾於民國（下同）112 年 7 月 1 日向甲借
款 500萬元，乙為該筆借款之連帶保證人，有乙用印之保證契約書為憑。
丙未遵期返還，甲就該借款債權聲請支付命令，已獲法院准許，且未經
丙聲明異議而告確定，有確定證明書為憑。為此請求乙應負保證人責任；
對此，乙則抗辯：甲未曾交付 500 萬元給丙，實則系爭債務為賭債，且
甲、乙間未曾訂定連帶保證契約，該保證契約書上乙之印章係被盜蓋云
云。問：
關於甲、丙間借款債權是否存在一事，乙是否受該確定支付命令之效
力所拘束，能否再事爭執？（10分）
關於系爭連帶保證契約之成立，及印章是否由乙用印或由他人盜蓋，
應由何人負舉證責任？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "934f5381fdcb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1012", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00073', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲涉犯槍砲彈藥刀械管制條例罪嫌，經檢察官提起公訴，審判期間，雖
檢察官依刑事訴訟法第 161條第1 項規定負舉證責任；然法官發現於案
內存在形式上不利被告之證據，檢察官未聲請調查，如未調查顯有影響
判決結果之虞，且有調查可能性，遂依刑事訴訟法第 273 條第 1 項第 5
款規定，曉諭檢察官為調查證據之聲請。請詳附理由說明法院所踐行之
程序是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "934f5381fdcb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1012", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00074', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲男以藥劑致乙女陷入意識模糊、全身無力癱臥在沙發上之狀態，甲見
狀不顧乙出言拒絕，仍以違反乙意願，對乙為強制性交行為。乙醒後立
即前往地檢署按鈴申告，檢察官指揮警察帶領乙至某醫院採集血液及尿
液並當場黏貼檢體封籤，放置冰箱冷藏保存，翌日由員警領出本件檢體，
交由檢察官囑託臺大醫學院進行鑑定，經臺大醫學院函附鑑定（諮詢）
案件回覆書（實際鑑定人 A有具名）所載，乙之血液及尿液確皆鑑定驗
出佐沛眠（安眠鎮靜劑）成分，檢察官遂以加重強制性交罪對甲提起公
訴，審判中甲之辯護人主張：「本件檢體於採集、保管及送鑑之過程，不
具同一性及該鑑定報告書，無證據能力。」惟法院以檢察官所提出證明
該證物監管鏈並無斷裂情形之證物監管鏈書，並無傳喚經手監管、移送
之人到庭作證，且法院亦認為不必要傳喚 A至法庭以言詞說明，即認定
甲有罪。請詳附理由說明法院所踐行之程序是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "934f5381fdcb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1012", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00075', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'essay', '甲 40 年前在自有 A 地興建 B 屋，B 屋已年久失修，漏水嚴重。甲為修
繕 B 屋，乃向乙借款新臺幣（下同）1,000 萬元，並以 B 屋為乙設定抵
押權。後甲將 B屋交由丙包工包料進行重大修繕，約定酬金 1,200 萬元，
然甲迄未支付。試問： 丙得否就 1,200 萬元報酬額，向甲請求對 B 屋
和 A地為其設定抵押權？（13 分） 若甲遲未清償對乙之借款，乙聲請
法院拍賣 B屋，丙之報酬債權與乙之借款債權，孰先受償？（12分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00076', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'essay', '甲母和其養女乙串通設局騙婚，由甲偽稱願將獨生女乙嫁與丙為妻，並
約定民國（下同）113 年 2 月14日訂婚，騙使丙於訂婚日致送價值新臺
幣（下同）500 萬元之鑽石項鏈、耳環與手鍊給乙。嗣乙又偽為同意於
同年 5 月 1日結婚，但於結婚當日乙卻不知去向，丙為置辦婚禮支出 100
萬元。112 年 10月丙於初識甲、乙母女之際，乙向丙透露家中有急需，
須辦理貸款。甲、乙隨後即向 A銀行貸款200萬元，約定二人負連帶責
丙知悉其被乙騙婚後，
不甘受損，其得向乙為如何主張？（13 分） 如A銀行同意主債務人甲
和乙延期清償，丙得為如何主張？（12 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00077', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '未保留胎兒應繼分之遺產協議分割行為，其效力為何？ 有效  無效  得撤銷  效力未定', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00078', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲將一平板電腦借乙使用，乙使用時，好友丙見到，非常羨慕，表示願以高價購買之，乙見機不 可失，遂以自己名義賣與丙，並將該平板電腦交付於丙。有關乙、丙間之法律行為，下列敘述， 何者正確？ 債權行為與物權行為均無效  債權行為與物權行為均效力未定 債權行為效力未定，物權行為無效  債權行為有效，物權行為效力未定', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00079', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列何種請求權，有消滅時效規定之適用？ 分割共有物之請求權  已登記不動產所有人之除去妨害請求權 夫妻間侵權行為而生之損害賠償請求權  夫妻關係而生之同居請求權 33120', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00080', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲有A跑車一部，A車因車禍致車體毀損。甲擅自取乙所有之油漆漆於A車，並向偷車集團購買 丙所有之同類新型引擎一個，安裝於A車。其後甲又將A車讓售於惡意之丁。下列敘述，何者正確？ 甲取得油漆之所有權，乙得依不當得利規定向甲請求償金 甲取得引擎之所有權，丙得依不當得利規定向甲請求償金 甲有權處分A車，丁不僅取得A車之所有權，亦取得油漆及引擎之所有權 乙得以其所有權受侵害為由，對惡意之丁主張侵權行為之損害賠償', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00081', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於錯誤意思表示之敘述，何者錯誤？ 甲欲與乙畫家締約，使乙畫家為甲畫肖像，但卻將丙畫家認為是乙畫家而與丙畫家締約，甲無 過失時，得撤銷其與丙間之契約 甲欲向丁購買A馬，卻未注意誤以為B馬為A馬而購買之，則甲得撤銷其與丁間之契約 甲內心欲以新臺幣（下同）300萬元出賣C車予戊，於書寫時寫成30萬元，甲無過失時，得撤 銷其與戊間之契約 甲以為前來應徵之庚，係曾在美國留學3年取得學位而與其訂立僱傭契約，甲無過失時，得撤 銷其與庚間之契約', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL)
